import{_ as e,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as d,o as i,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const W=JSON.parse('{"title":"WebDAV 설정과 접근","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/Safety/webdav-site-access.md","filePath":"ko-KR/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),r={name:"ko-KR/Safety/webdav-site-access.md"};function s(n,a,c,b,h,p){return i(),o("div",null,[...a[0]||(a[0]=[l('<h1 id="webdav-설정과-접근" tabindex="-1">WebDAV 설정과 접근 <a class="header-anchor" href="#webdav-설정과-접근" aria-label="Permalink to &quot;WebDAV 설정과 접근&quot;">​</a></h1><p>ImgBed는 WebDAV를 통해 파일에 접근할 수 있습니다. PC의 파일 탐색기나 WebDAV 클라이언트에서 연결하면 저장된 파일을 드라이브처럼 확인할 수 있습니다.</p><h2 id="사용-사례" tabindex="-1">사용 사례 <a class="header-anchor" href="#사용-사례" aria-label="Permalink to &quot;사용 사례&quot;">​</a></h2><ul><li>Windows나 macOS에서 파일을 직접 확인하고 싶을 때.</li><li>WebDAV 지원 클라이언트로 파일을 정리하고 싶을 때.</li><li>관리자 화면 외부에서 저장된 파일에 접근해야 할 때.</li></ul><h2 id="windows-11에서-연결하기" tabindex="-1">Windows 11에서 연결하기 <a class="header-anchor" href="#windows-11에서-연결하기" aria-label="Permalink to &quot;Windows 11에서 연결하기&quot;">​</a></h2><ol><li>파일 탐색기를 엽니다.</li><li><code>내 PC</code>를 오른쪽 클릭합니다.</li><li><code>네트워크 위치 추가</code>를 선택합니다.</li><li>WebDAV URL을 입력합니다.</li><li>사용자 이름과 비밀번호를 입력합니다.</li><li>연결 후 폴더처럼 열리는지 확인합니다.</li></ol><p><img src="'+e+'" alt="Windows 11 WebDAV 설정" loading="lazy"></p><p>연결에 성공하면 탐색기에서 WebDAV 내용을 볼 수 있습니다.</p><p><img src="'+t+'" alt="Windows 표시" loading="lazy"></p><h2 id="인증-정보" tabindex="-1">인증 정보 <a class="header-anchor" href="#인증-정보" aria-label="Permalink to &quot;인증 정보&quot;">​</a></h2><p>WebDAV 사용자 이름과 비밀번호는 ImgBed에 설정된 인증 정보를 사용합니다. 공개용 계정보다는 필요한 범위의 권한만 가진 계정을 쓰는 편이 안전합니다.</p><h2 id="연결이-안-될-때" tabindex="-1">연결이 안 될 때 <a class="header-anchor" href="#연결이-안-될-때" aria-label="Permalink to &quot;연결이 안 될 때&quot;">​</a></h2><table tabindex="0"><thead><tr><th>확인 항목</th><th>내용</th></tr></thead><tbody><tr><td>URL</td><td><code>https://</code>를 포함한 올바른 WebDAV 주소인지</td></tr><tr><td>인증 정보</td><td>사용자 이름과 비밀번호가 맞는지</td></tr><tr><td>권한</td><td>대상 디렉터리에 읽기/쓰기 권한이 있는지</td></tr><tr><td>클라이언트</td><td>Windows 또는 클라이언트가 WebDAV 접속을 제한하지 않는지</td></tr></tbody></table><p>용량 조회만 실패하고 파일 업로드는 되는 경우도 있습니다. 이때는 WebDAV 서버가 용량 정보를 제공하지 않는 것일 수 있습니다.</p>',14)])])}const f=d(r,[["render",s]]);export{W as __pageData,f as default};
